{
  "name": "kuchup-homepage",
  "private": true,
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start",
    "lint": "next lint"
  },
  "dependencies": {
    "next": "^15.3.0",
    "react": "^19.1.0",
    "react-dom": "^19.1.0"
  },
  "devDependencies": {
    "@types/node": "^22.15.0",
    "@types/react": "^19.1.0",
    "@types/react-dom": "^19.1.0",
    "autoprefixer": "^10.4.21",
    "postcss": "^8.5.3",
    "tailwindcss": "^3.4.17",
    "typescript": "^5.8.3"
  }
}

import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  reactStrictMode: true,
};

export default nextConfig;

/** @type {import('postcss-load-config').Config} */
const config = {
  plugins: {
    tailwindcss: {},
    autoprefixer: {},
  },
};

export default config;

import type { Config } from "tailwindcss";

const config: Config = {
  content: [
    "./app/**/*.{js,ts,jsx,tsx,mdx}",
    "./components/**/*.{js,ts,jsx,tsx,mdx}",
  ],
  theme: {
    extend: {
      colors: {
        graphite: "#0B0E11",
        offwhite: "#E8E6E1",
        panel: "#1B2430",
        hairline: "#2A3038",
        amber: "#FF8A00",
        teal: "#4FD1C5",
      },
      fontFamily: {
        mono: ["var(--font-ibm-plex-mono)", "ui-monospace", "monospace"],
        sans: ["var(--font-inter)", "system-ui", "sans-serif"],
      },
      borderRadius: {
        DEFAULT: "2px",
        sm: "2px",
        md: "4px",
        lg: "4px",
      },
      maxWidth: {
        site: "72rem",
      },
    },
  },
  plugins: [],
};

export default config;

@import "tailwindcss/base";
@import "tailwindcss/components";
@import "tailwindcss/utilities";

:root {
  color-scheme: dark;
}

html {
  scroll-behavior: smooth;
}

body {
  @apply bg-graphite text-offwhite font-sans antialiased;
}

:focus-visible {
  @apply outline outline-2 outline-offset-2 outline-amber;
}

@keyframes live-pulse {
  0%,
  100% {
    opacity: 1;
    transform: scale(1);
  }
  50% {
    opacity: 0.45;
    transform: scale(0.85);
  }
}

.live-dot {
  animation: live-pulse 2.4s ease-in-out infinite;
}

@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: auto;
  }

  .live-dot {
    animation: none;
  }
}

@keyframes flap-flip {
  0% {
    transform: rotateX(0deg);
  }
  45% {
    transform: rotateX(-90deg);
  }
  55% {
    transform: rotateX(-90deg);
  }
  100% {
    transform: rotateX(0deg);
  }
}

.flap-cell-inner.flipping {
  animation: flap-flip 0.12s ease-in forwards;
}

@media (prefers-reduced-motion: reduce) {
  .flap-cell-inner.flipping {
    animation: none;
  }
}

import type { Metadata } from "next";
import { IBM_Plex_Mono, Inter } from "next/font/google";
import "./globals.css";

const inter = Inter({
  subsets: ["latin"],
  variable: "--font-inter",
  display: "swap",
});

const ibmPlexMono = IBM_Plex_Mono({
  subsets: ["latin"],
  weight: ["400", "500", "600"],
  variable: "--font-ibm-plex-mono",
  display: "swap",
});

export const metadata: Metadata = {
  title: "kuchup | Relocation Jobs",
  description:
    "Self-hosted job discovery and application tracking for EU relocation-friendly software roles. One catalog, 25 ATS integrations, Postgres-backed.",
  openGraph: {
    title: "kuchup | Relocation Jobs",
    description:
      "Self-hosted ATS scraping and application tracking for relocation-friendly software roles in Europe.",
    url: "https://kuchup.com/",
    siteName: "kuchup",
    type: "website",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" className={`${inter.variable} ${ibmPlexMono.variable}`}>
      <body className="min-h-screen">{children}</body>
    </html>
  );
}

import { Footer } from "@/components/Footer";
import { Header } from "@/components/Header";
import { Hero } from "@/components/Hero";
import { PipelineDiagram } from "@/components/PipelineDiagram";
import { StackTable } from "@/components/StackTable";
import { StatsStrip } from "@/components/StatsStrip";

export default function HomePage() {
  return (
    <div className="min-h-screen flex flex-col">
      <Header />
      <main className="flex-1">
        <Hero />
        <PipelineDiagram />
        <StatsStrip />
        <StackTable />
      </main>
      <Footer />
    </div>
  );
}

const GITHUB_URL = "https://github.com/AminMortezaie/relocation-jobs";
const DOCS_URL =
  "https://github.com/AminMortezaie/relocation-jobs/blob/main/docs/README.md";
const BOARD_URL = "https://kuchup.com/panel";

const NAV_LINKS = [
  { href: BOARD_URL, label: "Board" },
  { href: DOCS_URL, label: "Docs" },
  { href: GITHUB_URL, label: "GitHub" },
] as const;

export function Header() {
  return (
    <header className="border-b border-hairline">
      <div className="mx-auto flex max-w-site items-center justify-between gap-6 px-4 py-4 sm:px-6">
        <a
          href="/"
          className="font-mono text-sm font-medium uppercase tracking-[0.18em] text-offwhite"
        >
          kuchup
        </a>

        <div className="flex items-center gap-6">
          <div
            className="flex items-center gap-2 font-mono text-[10px] uppercase tracking-widest text-teal"
            aria-label="System live"
          >
            <span
              className="live-dot inline-block h-1.5 w-1.5 rounded-full bg-teal"
              aria-hidden="true"
            />
            Live
          </div>

          <nav aria-label="Primary">
            <ul className="flex items-center gap-4 sm:gap-6">
              {NAV_LINKS.map((link) => (
                <li key={link.label}>
                  <a
                    href={link.href}
                    className="font-mono text-xs uppercase tracking-wider text-offwhite/70 transition-colors hover:text-offwhite"
                    {...(link.href.startsWith("http")
                      ? { target: "_blank", rel: "noopener noreferrer" }
                      : {})}
                  >
                    {link.label}
                  </a>
                </li>
              ))}
            </ul>
          </nav>
        </div>
      </div>
    </header>
  );
}

"use client";

import { useEffect, useMemo, useState } from "react";

export type BoardRow = {
  city: string;
  company: string;
  stack: string;
  status: string;
  statusTone?: "live" | "amber" | "muted";
};

const BOARD_ROWS: BoardRow[] = [
  {
    city: "BERLIN",
    company: "WOLT",
    stack: "GO",
    status: "SCRAPED 6H AGO",
    statusTone: "live",
  },
  {
    city: "AMSTERDAM",
    company: "POLARSTEPS",
    stack: "PYTHON",
    status: "APPLIED",
    statusTone: "amber",
  },
  {
    city: "HAMBURG",
    company: "SCAYLE",
    stack: "GO",
    status: "CV READY",
    statusTone: "muted",
  },
  {
    city: "LONDON",
    company: "FENERGO",
    stack: "JAVA",
    status: "SCRAPED 3H AGO",
    statusTone: "live",
  },
  {
    city: "LISBON",
    company: "REMOTE",
    stack: "REACT",
    status: "LOOKING",
    statusTone: "muted",
  },
];

const FLIP_POOL = "REDACTED";
const FLIP_CYCLES = 4;
const FLIP_INTERVAL_MS = 55;
const ROW_STAGGER_MS = 80;
const CHAR_STAGGER_MS = 12;

function useMediaQuery(query: string) {
  const [matches, setMatches] = useState(false);

  useEffect(() => {
    const media = window.matchMedia(query);
    const update = () => setMatches(media.matches);
    update();
    media.addEventListener("change", update);
    return () => media.removeEventListener("change", update);
  }, [query]);

  return matches;
}

function useShouldAnimate() {
  const isMobile = useMediaQuery("(max-width: 479px)");
  const reducedMotion = useMediaQuery("(prefers-reduced-motion: reduce)");
  return !isMobile && !reducedMotion;
}

function statusClass(tone: BoardRow["statusTone"]) {
  if (tone === "live") return "text-teal";
  if (tone === "amber") return "text-amber";
  return "text-offwhite/55";
}

function FlipChar({
  target,
  delay,
  animate,
}: {
  target: string;
  delay: number;
  animate: boolean;
}) {
  const [display, setDisplay] = useState(animate ? " " : target);
  const [flipping, setFlipping] = useState(false);
  const isSpace = target === " ";

  useEffect(() => {
    if (!animate) {
      setDisplay(target);
      return;
    }

    let cycle = 0;
    let intervalId: ReturnType<typeof setInterval> | undefined;
    const startId = window.setTimeout(() => {
      intervalId = window.setInterval(() => {
        if (cycle < FLIP_CYCLES) {
          setFlipping(true);
          setDisplay(
            FLIP_POOL[Math.floor(Math.random() * FLIP_POOL.length)] ?? " ",
          );
          window.setTimeout(() => setFlipping(false), 90);
          cycle += 1;
        } else {
          setDisplay(target);
          if (intervalId) window.clearInterval(intervalId);
        }
      }, FLIP_INTERVAL_MS);
    }, delay);

    return () => {
      window.clearTimeout(startId);
      if (intervalId) window.clearInterval(intervalId);
    };
  }, [animate, delay, target]);

  if (isSpace) {
    return <span className="inline-block w-[0.35em]" aria-hidden="true" />;
  }

  return (
    <span
      className="inline-block h-[1.35em] w-[0.62em] overflow-hidden border border-hairline bg-panel align-bottom"
      aria-hidden="true"
    >
      <span
        className={`flap-cell-inner flex h-full items-center justify-center font-mono text-[0.72rem] font-medium leading-none text-amber sm:text-xs ${
          flipping ? "flipping" : ""
        }`}
        style={{ transformStyle: "preserve-3d" }}
      >
        {display}
      </span>
    </span>
  );
}

function FlipText({
  text,
  baseDelay,
  animate,
}: {
  text: string;
  baseDelay: number;
  animate: boolean;
}) {
  const chars = useMemo(() => text.split(""), [text]);

  return (
    <span className="inline-flex flex-wrap items-end gap-px" aria-hidden="true">
      {chars.map((char, index) => (
        <FlipChar
          key={`${text}-${index}`}
          target={char}
          delay={baseDelay + index * CHAR_STAGGER_MS}
          animate={animate}
        />
      ))}
    </span>
  );
}

function AnimatedRow({
  row,
  rowIndex,
  animate,
}: {
  row: BoardRow;
  rowIndex: number;
  animate: boolean;
}) {
  const baseDelay = rowIndex * ROW_STAGGER_MS;

  return (
    <div
      className="grid grid-cols-[minmax(0,1fr)_auto] items-end gap-x-3 gap-y-2 border-b border-hairline py-3 last:border-b-0 sm:grid-cols-[7.5rem_1fr_5rem_1fr] sm:gap-x-4"
      role="listitem"
    >
      <div className="min-w-0">
        <FlipText text={row.city} baseDelay={baseDelay} animate={animate} />
        <span className="sr-only">{row.city}</span>
      </div>

      <span className="hidden font-mono text-amber/60 sm:inline" aria-hidden="true">
        ·
      </span>

      <div className="min-w-0 sm:col-start-auto">
        <FlipText
          text={row.company}
          baseDelay={baseDelay + 40}
          animate={animate}
        />
        <span className="sr-only">{row.company}</span>
      </div>

      <span className="hidden font-mono text-amber/60 sm:inline" aria-hidden="true">
        ·
      </span>

      <div className="min-w-0">
        <FlipText
          text={row.stack}
          baseDelay={baseDelay + 80}
          animate={animate}
        />
        <span className="sr-only">{row.stack}</span>
      </div>

      <div
        className={`col-span-2 text-right font-mono text-[10px] uppercase tracking-wider sm:col-span-1 sm:text-xs ${statusClass(row.statusTone)}`}
      >
        {animate ? (
          <>
            <FlipText
              text={row.status}
              baseDelay={baseDelay + 120}
              animate={animate}
            />
            <span className="sr-only">{row.status}</span>
          </>
        ) : (
          row.status
        )}
      </div>
    </div>
  );
}

function StaticRow({ row }: { row: BoardRow }) {
  return (
    <article className="border border-hairline bg-panel p-3">
      <dl className="grid gap-2 font-mono text-xs">
        <div className="flex justify-between gap-3">
          <dt className="text-offwhite/45">City</dt>
          <dd className="text-amber">{row.city}</dd>
        </div>
        <div className="flex justify-between gap-3">
          <dt className="text-offwhite/45">Company</dt>
          <dd>{row.company}</dd>
        </div>
        <div className="flex justify-between gap-3">
          <dt className="text-offwhite/45">Stack</dt>
          <dd>{row.stack}</dd>
        </div>
        <div className="flex justify-between gap-3 border-t border-hairline pt-2">
          <dt className="text-offwhite/45">Status</dt>
          <dd className={statusClass(row.statusTone)}>{row.status}</dd>
        </div>
      </dl>
    </article>
  );
}

export function FlapBoard() {
  const shouldAnimate = useShouldAnimate();
  const isMobile = useMediaQuery("(max-width: 479px)");

  return (
    <section
      className="border border-hairline bg-panel"
      aria-label="Catalog departures board"
    >
      <div className="flex items-center justify-between border-b border-hairline px-3 py-2 sm:px-4">
        <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-offwhite/50">
          Departures
        </p>
        <p className="font-mono text-[10px] uppercase tracking-[0.2em] text-teal">
          Catalog feed
        </p>
      </div>

      {isMobile ? (
        <div className="grid gap-2 p-3" role="list">
          {BOARD_ROWS.map((row) => (
            <StaticRow key={`${row.city}-${row.company}`} row={row} />
          ))}
        </div>
      ) : (
        <div className="hidden px-3 pb-1 pt-2 sm:block sm:px-4" role="list">
          <div
            className="mb-2 hidden font-mono text-[10px] uppercase tracking-widest text-offwhite/35 sm:grid sm:grid-cols-[7.5rem_1fr_5rem_1fr] sm:gap-x-4"
            aria-hidden="true"
          >
            <span>City</span>
            <span className="col-start-3">Company</span>
            <span>Stack</span>
            <span className="text-right">Status</span>
          </div>
          {BOARD_ROWS.map((row, index) => (
            <AnimatedRow
              key={`${row.city}-${row.company}`}
              row={row}
              rowIndex={index}
              animate={shouldAnimate}
            />
          ))}
        </div>
      )}
    </section>
  );
}

const METRICS = [
  {
    label: "ATS types",
    value: "25",
    note: "Greenhouse, Lever, Ashby, Personio, Workable, Workday, …",
  },
  {
    label: "Test suite",
    value: "299",
    note: "pytest collected; 90% coverage gate on business modules",
  },
  {
    label: "Board load (DE)",
    value: "89s → 1.7s",
    note: "measured incident; cache + preview pass removed",
  },
  {
    label: "Scrape concurrency",
    value: "16",
    note: "asyncio + httpx; hard cap in ats_constants",
  },
  {
    label: "Catalog refresh",
    value: "6h",
    note: "EC2 fetch worker; Playwright fallback",
  },
] as const;

export function StatsStrip() {
  return (
    <section
      className="border-b border-hairline"
      aria-labelledby="stats-heading"
    >
      <div className="mx-auto max-w-site px-4 py-10 sm:px-6">
        <h2
          id="stats-heading"
          className="mb-4 font-mono text-xs uppercase tracking-[0.2em] text-offwhite/50"
        >
          Documented metrics
        </h2>

        <div className="divide-y divide-hairline border border-hairline bg-panel">
          {METRICS.map((metric) => (
            <div
              key={metric.label}
              className="grid gap-1 px-3 py-3 sm:grid-cols-[9rem_8rem_1fr] sm:items-baseline sm:gap-4 sm:px-4"
            >
              <span className="font-mono text-[10px] uppercase tracking-wider text-offwhite/45">
                {metric.label}
              </span>
              <span className="font-mono text-sm font-medium text-amber">
                {metric.value}
              </span>
              <span className="font-mono text-[10px] leading-relaxed text-offwhite/50 sm:text-xs">
                {metric.note}
              </span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

const GITHUB_URL = "https://github.com/AminMortezaie/relocation-jobs";
const DOCS_URL =
  "https://github.com/AminMortezaie/relocation-jobs/blob/main/docs/contributing.md";
const BOARD_URL = "https://kuchup.com/panel";

const FOOTER_LINKS = [
  { href: BOARD_URL, label: "Board" },
  { href: DOCS_URL, label: "Contributing" },
  { href: GITHUB_URL, label: "Source" },
] as const;

export function Footer() {
  return (
    <footer className="border-t border-hairline">
      <div className="mx-auto flex max-w-site flex-col gap-3 px-4 py-6 text-sm text-offwhite/50 sm:flex-row sm:items-center sm:justify-between sm:px-6">
        <p className="font-mono text-xs uppercase tracking-wider">
          kuchup · relocation jobs
        </p>
        <nav aria-label="Footer">
          <ul className="flex flex-wrap gap-4">
            {FOOTER_LINKS.map((link) => (
              <li key={link.label}>
                <a
                  href={link.href}
                  className="font-mono text-xs uppercase tracking-wider text-offwhite/50 transition-colors hover:text-offwhite"
                  {...(link.href.startsWith("http")
                    ? { target: "_blank", rel: "noopener noreferrer" }
                    : {})}
                >
                  {link.label}
                </a>
              </li>
            ))}
          </ul>
        </nav>
      </div>
    </footer>
  );
}

