type RoleSearchFormProps = {
  id?: string;
  compact?: boolean;
};

export function RoleSearchForm({ id, compact = false }: RoleSearchFormProps) {
  const roleId = useId();
  const countryId = useId();

  function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const data = new FormData(event.currentTarget);
    const role = String(data.get("role") || "all");
    const country = String(data.get("country") || "all");
    const params = new URLSearchParams();
    if (role !== "all") params.set("q", role);
    if (country !== "all") params.set("country", country);
    const query = params.toString();
    window.location.href = query ? `/panel?${query}` : "/panel";
  }

  return (
    <form
      id={id}
      onSubmit={handleSubmit}
      className={`flex flex-col gap-2 sm:flex-row sm:items-stretch ${compact ? "" : "sm:gap-3"}`}
    >
      <label className="sr-only" htmlFor={roleId}>
        Role or stack
      </label>
      <div className="relative min-w-0 flex-1">
        <StackIcon />
        <select
          id={roleId}
          name="role"
          defaultValue="all"
          className="w-full appearance-none rounded-full border border-white/[0.09] bg-bg-elevated py-3 pl-10 pr-10 text-sm text-text focus:border-accent focus:outline-none focus:ring-[3px] focus:ring-[rgba(91,141,239,0.14)]"
        >
          {ROLES.map((option) => (
            <option key={option.value} value={option.value}>
              {option.label}
            </option>
          ))}
        </select>
        <Chevron />
      </div>

      <label className="sr-only" htmlFor={countryId}>
        Country
      </label>
      <div className="relative min-w-0 flex-1 sm:max-w-[11rem]">
        <GlobeIcon />
        <select
          id={countryId}
          name="country"
          defaultValue="all"
          className="w-full appearance-none rounded-full border border-white/[0.09] bg-bg-elevated py-3 pl-10 pr-10 text-sm text-text focus:border-accent focus:outline-none focus:ring-[3px] focus:ring-[rgba(91,141,239,0.14)]"
        >
          {COUNTRIES.map((option) => (
            <option key={option.value} value={option.value}>
              {option.label}
            </option>
          ))}
        </select>
        <Chevron />
      </div>

      <button
        type="submit"
        className="inline-flex shrink-0 items-center justify-center rounded-full bg-accent px-5 py-3 text-sm font-semibold text-white transition-colors hover:bg-accent-hover"
      >
        Search roles
      </button>
    </form>
  );
}

