  font-weight: 600;
  letter-spacing: -0.02em;
}

/* ── Premium surfaces ── */

.surface-card {
  background: linear-gradient(165deg, var(--surface-top) 0%, var(--surface-bottom) 100%);
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.07),
    0 4px 16px rgba(0, 0, 0, 0.22);
}

.surface-card-interactive {
  transition:
    transform 280ms cubic-bezier(0.16, 1, 0.3, 1),
    border-color 280ms cubic-bezier(0.16, 1, 0.3, 1),
    box-shadow 280ms cubic-bezier(0.16, 1, 0.3, 1);
}

.surface-card-interactive:hover {
  transform: translateY(-2px);
  border-color: rgba(255, 255, 255, 0.12);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.1),
    0 8px 28px rgba(56, 189, 248, 0.08),
    0 4px 16px rgba(0, 0, 0, 0.24);
}

/* ── Hero glow ── */

.hero-search-glow {
  position: relative;
  isolation: isolate;
}

.hero-search-glow::before {
  content: "";
  position: absolute;
  inset: -48% -8% -32%;
  z-index: -1;
  background: radial-gradient(
    ellipse at 50% 55%,
    rgba(91, 141, 239, 0.2) 0%,
    rgba(167, 139, 250, 0.1) 38%,
    transparent 68%
  );
  filter: blur(42px);
  opacity: 0.75;
  pointer-events: none;
  transition: opacity 200ms ease, filter 200ms ease;
}

.hero-search-glow:focus-within::before {
  opacity: 1;
  filter: blur(48px);
}

/* ── Form controls ── */

.select-pill {
  @apply w-full appearance-none rounded-full border border-white/[0.08] py-3 pl-10 pr-10 text-sm font-normal text-text;
  background: linear-gradient(180deg, #111620 0%, #0d1118 100%);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
  transition:
    border-color 200ms ease,
    box-shadow 200ms ease;
}

.select-pill:focus {
  outline: none;
  border-color: rgba(91, 141, 239, 0.55);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.06),
    0 0 0 3px rgba(91, 141, 239, 0.14);
}

.select-icon {
  top: calc(50% + 0.5px);
  transform: translateY(-50%);
}

/* ── Primary button ── */

.btn-primary {
  background: linear-gradient(180deg, #6b96f5 0%, #5b8def 52%, #4a7ad8 100%);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.14),
    0 2px 8px rgba(91, 141, 239, 0.28);
  transition:
    filter 200ms ease,
    box-shadow 200ms ease,
    transform 200ms ease;
}

.btn-primary:hover {
  filter: brightness(1.07);
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.18),
    0 4px 14px rgba(91, 141, 239, 0.34);
}

.btn-primary:active {
  transform: translateY(1px);
}

/* ── Focus rings ── */

:focus {
  outline: none;
}

:focus-visible {
  outline: none;
  box-shadow:
    0 0 0 2px var(--page-base),
    0 0 0 4px rgba(91, 141, 239, 0.72);
}

/* ── Section rhythm ── */

.section-major {
  padding-top: 6rem;
  padding-bottom: 6rem;
}

@media (min-width: 1024px) {
  .section-major {
    padding-top: 8rem;
    padding-bottom: 8rem;
  }
}

.section-major-first {
  padding-top: 3rem;
  padding-bottom: 6rem;
}

@media (min-width: 1024px) {
  .section-major-first {
    padding-top: 4rem;
    padding-bottom: 8rem;
  }
}

/* ── Entrance (page load) ── */

@keyframes fade-up {
  from {
    opacity: 0;
    transform: translateY(16px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.hero-enter {
  animation: fade-up 400ms cubic-bezier(0.16, 1, 0.3, 1) both;
}

.hero-enter-delay-1 {
  animation-delay: 80ms;
}

.hero-enter-delay-2 {
  animation-delay: 160ms;
}

/* ── Scroll reveal ── */

.reveal-card {
  opacity: 0;
  transform: translateY(12px);
  transition:
    opacity 500ms cubic-bezier(0.16, 1, 0.3, 1),
    transform 500ms cubic-bezier(0.16, 1, 0.3, 1);
}

.reveal-card.is-visible {
  opacity: 1;
  transform: translateY(0);
}

/* ── Alive pill cross-fade ── */

@keyframes pill-fade {
  0%,
  42% {
    opacity: 1;
  }
  50%,
  92% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}

.alive-pill-layer {
  animation: pill-fade 5s ease-in-out infinite;
}

.alive-pill-layer--alt {
  animation: pill-fade 5s ease-in-out infinite;
  animation-delay: -2.5s;
}

/* ── Reduced motion ── */

@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: auto;
  }

  .hero-enter,
  .hero-enter-delay-1,
  .hero-enter-delay-2 {
    animation: none;
  }

  .reveal-card {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .surface-card-interactive {
    transition: border-color 200ms ease;
  }

  .surface-card-interactive:hover {
    transform: none;
  }

  .alive-pill-layer,
  .alive-pill-layer--alt {
    animation: none;
  }

  .hero-search-glow::before {
    transition: none;
  }

  .btn-primary {
    transition: none;
  }

  .btn-primary:active {
    transform: none;
  }
}

