"use client";

import { useEffect, useState } from "react";
import { Pill, type PillVariant } from "@/components/ui/Pill";

type AlivePillProps = {
  states: { variant: PillVariant; label: string }[];
};

export function AlivePill({ states }: AlivePillProps) {
  const [reducedMotion, setReducedMotion] = useState(false);

  useEffect(() => {
    const media = window.matchMedia("(prefers-reduced-motion: reduce)");
    const update = () => setReducedMotion(media.matches);
    update();
    media.addEventListener("change", update);
    return () => media.removeEventListener("change", update);
  }, []);

  if (reducedMotion || states.length < 2) {
    return <Pill variant={states[0].variant}>{states[0].label}</Pill>;
  }

  const [first, second] = states;

  return (
    <span className="relative inline-grid place-items-start">
      <span className="alive-pill-layer col-start-1 row-start-1">
        <Pill variant={first.variant}>{first.label}</Pill>
      </span>
      <span className="alive-pill-layer--alt col-start-1 row-start-1">
        <Pill variant={second.variant}>{second.label}</Pill>
      </span>
    </span>
  );
}

"use client";

import { useEffect, useRef, useState } from "react";

export function useInView<T extends HTMLElement>(threshold = 0.15) {
  const ref = useRef<T>(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const node = ref.current;
    if (!node) return;

    const reduced = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (reduced) {
      setVisible(true);
      return;
    }

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry?.isIntersecting) {
          setVisible(true);
          observer.disconnect();
        }
      },
      { threshold },
    );

    observer.observe(node);
    return () => observer.disconnect();
  }, [threshold]);

  return { ref, visible };
}

