"use client";

import { FormEvent, useId } from "react";

const ROLES = [
  { value: "all", label: "All roles" },
  { value: "backend", label: "Backend" },
  { value: "python", label: "Python" },
  { value: "go", label: "Go" },
  { value: "java", label: "Java" },
  { value: "react", label: "React / Frontend" },
  { value: "devops", label: "DevOps / Platform" },
] as const;

const COUNTRIES = [
  { value: "all", label: "All countries" },
  { value: "germany", label: "Germany" },
  { value: "netherlands", label: "Netherlands" },
  { value: "uk", label: "UK" },
  { value: "portugal", label: "Portugal" },
  { value: "ireland", label: "Ireland" },
] as const;

type SearchBarProps = {
  id?: string;
  compact?: boolean;
};

export function SearchBar({ id, compact = false }: SearchBarProps) {
  const roleId = useId();
  const countryId = useId();

  function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const data = new FormData(event.currentTarget);
    const role = String(data.get("role") || "all");
    const country = String(data.get("country") || "all");
    const params = new URLSearchParams();
    if (role !== "all") params.set("q", role);
    if (country !== "all") params.set("country", country);
    const query = params.toString();
    window.location.href = query ? `/panel?${query}` : "/panel";
  }

  return (
    <form
      id={id}
      onSubmit={handleSubmit}
      className={`flex flex-col gap-2 sm:flex-row sm:items-stretch ${compact ? "" : "sm:gap-3"}`}
    >
      <label className="sr-only" htmlFor={roleId}>
        Role or stack
      </label>
      <div className="relative min-w-0 flex-1">
        <StackIcon />
        <select id={roleId} name="role" defaultValue="all" className="select-pill">
          {ROLES.map((option) => (
            <option key={option.value} value={option.value}>
              {option.label}
            </option>
          ))}
        </select>
        <Chevron />
      </div>

      <label className="sr-only" htmlFor={countryId}>
        Country
      </label>
      <div className="relative min-w-0 flex-1 sm:max-w-[11rem]">
        <GlobeIcon />
        <select id={countryId} name="country" defaultValue="all" className="select-pill">
          {COUNTRIES.map((option) => (
            <option key={option.value} value={option.value}>
              {option.label}
            </option>
          ))}
        </select>
        <Chevron />
      </div>

      <button
        type="submit"
        className="btn-primary inline-flex shrink-0 items-center justify-center rounded-full px-5 py-3 text-sm font-semibold text-white"
      >
        Search roles
      </button>
    </form>
  );
}

function StackIcon() {
  return (
    <svg
      className="select-icon pointer-events-none absolute left-3.5 h-[15px] w-[15px] text-muted"
      viewBox="0 0 24 24"
